// OutputNode.jsx
import { useState } from 'react';
import { Handle, Position } from 'reactflow';
import './node.css';

export const OutputNode = ({ id, data }) => {
  const [currName, setCurrName] = useState(
    data?.outputName || id.replace('customOutput-', 'output_')
  );
  const [outputType, setOutputType] = useState(data?.outputType || 'Text');

  const handleNameChange = (e) => {
    setCurrName(e.target.value);
    data.outputName = e.target.value; // sync with React Flow node data
  };

  const handleTypeChange = (e) => {
    setOutputType(e.target.value);
    data.outputType = e.target.value; // sync with React Flow node data
  };

  return (
    <div className="vs-node output-node">
      {/* Input handle */}
      <Handle type="target" position={Position.Left} id={`${id}-value`} />

      <div className="vs-node-header">Output</div>
      <div className="vs-node-body">
        <label htmlFor={`${id}-name`}>
          Name:
          <input
            id={`${id}-name`}
            type="text"
            value={currName}
            onChange={handleNameChange}
          />
        </label>
        <label htmlFor={`${id}-type`}>
          Type:
          <select
            id={`${id}-type`}
            value={outputType}
            onChange={handleTypeChange}
          >
            <option value="Text">Text</option>
            <option value="Image">Image</option>
          </select>
        </label>
      </div>
    </div>
  );
};
